def cargar_tipos_doc_personalizados(archivo):
    """Lee informe de tipos de documentos del cliente y retorna set de códigos.
    Lector flexible: encuentra la fila de encabezados y la columna 'Código'
    automáticamente, sin exigir un número exacto de columnas (los informes
    del sistema pueden traer columnas extra como 'Fecha impresión')."""
    try:
        raw = pd.read_excel(archivo, header=None, engine='openpyxl')
        # Buscar el encabezado "Código" en las primeras 10 filas
        fila_h, col_cod = None, None
        for i in range(min(10, len(raw))):
            for j in range(raw.shape[1]):
                v = str(raw.iat[i, j]).strip().lower().replace('ó', 'o')
                if v in ('codigo', 'cod', 'cod.'):
                    fila_h, col_cod = i, j
                    break
            if fila_h is not None:
                break
        if fila_h is None:
            # Respaldo: estructura clásica (encabezados en fila 4, primera columna)
            fila_h, col_cod = 3, 0
        serie = raw.iloc[fila_h + 1:, col_cod].dropna()
        codigos = set(serie.astype(str).str.strip().str.upper().tolist())
        codigos = {c for c in codigos if 1 <= len(c) <= 4 and c not in ('NAN', 'NONE', '<NA>')}
        return codigos
    except:
        return set()

def tiene_caracteres_especiales(v):
    return bool(re.search(r'[^0-9\s]', str(v).strip())) if str(v).strip() not in ('', 'nan', 'NAN', 'None', 'NONE', 'NaN', '<NA>') else False

def es_numerico(v):
    try: float(str(v).replace(',', '').strip()); return True
    except: return False

def es_fecha_valida(v):
    s = str(v).strip()
    if s in ('', 'nan', 'NAN', 'None', 'NONE', 'NaN', '<NA>'): return False
    for fmt in ('%d/%m/%Y', '%Y-%m-%d', '%d-%m-%Y', '%Y/%m/%d'):
        try: datetime.strptime(s.split(' ')[0], fmt); return True
        except: pass
    return False

def limpiar_nit(v):
    try: return str(int(float(str(v).replace(',','').strip().lstrip("'"))))
    except: return str(v).strip().lstrip("'")

def limpiar_codigo(v):
    """Normaliza códigos (cuenta, CC) leídos por pandas como float: '13059512.0' → '13059512'.
    Solo quita el .0 cuando el valor es un entero genuino; valores inválidos quedan intactos."""
    s = str(v).strip().lstrip("'")
    if re.fullmatch(r'\d+\.0+', s):
        s = s.split('.')[0]
    return s

def fmt_num(v):
    try: return f"{float(v):,.2f}"
    except: return str(v)

def parsear_puc_referencia(archivo):
    """Lee el PUC desde el informe del sistema SINCO (Cuentas contables) o desde la
    plantilla de migración (hoja MIGRACION), con detección automática del formato.
    Retorna (info, etiqueta): info = dict código → {tipo, req_ter, req_cc, equiv};
    etiqueta = 'PRINCIPAL' / 'FISCAL' si el informe lo indica, o ''.
    Retorna (None, '') si no se puede leer."""
    def _si(v):
        return str(v).strip().upper().replace('Í', 'I') in ('S', 'SI')

    # ── Formato 1: plantilla de migración (hoja MIGRACION) ──
    try:
        archivo.seek(0)
        df = pd.read_excel(archivo, sheet_name='MIGRACION', header=0, engine='openpyxl',
                           keep_default_na=False, na_values=[''])
        if 'Código' in df.columns and 'Tipo' in df.columns:
            tiene_equiv = 'Equivalencia' in df.columns
            info = {}
            for _, row in df.iterrows():
                cod = normalizar_codigo(row.get('Código',''))
                if not cod or vacia(cod): continue
                equiv_raw = row.get('Equivalencia','') if tiene_equiv else ''
                info[cod] = {
                    'tipo': str(row.get('Tipo','')).strip().upper()[:1],
                    'req_ter': _si(row.get('Requiere Tercero','')),
                    'req_cc': _si(row.get('Requiere Centro Costo','')),
                    'req_base': _si(row.get('Requiere Base','')),
                    'equiv': normalizar_codigo(equiv_raw) if not vacia(equiv_raw) else '',
                }
            if info: return info, ''
    except Exception:
        pass

    # ── Formato 2: informe del sistema (Cuentas contables) ──
    try:
        archivo.seek(0)
        crudo = pd.read_excel(archivo, header=None, engine='openpyxl', nrows=12)
        etiqueta, fila_hdr = '', None
        for i in range(len(crudo)):
            c0 = str(crudo.iloc[i, 0]).strip()
            if c0.upper().startswith('PUC:'):
                etiqueta = c0.split(':', 1)[1].strip().upper()
            if c0.lower() == 'cuenta contable':
                fila_hdr = i
                break
        if fila_hdr is None:
            return None, ''
        archivo.seek(0)
        df = pd.read_excel(archivo, header=fila_hdr, engine='openpyxl',
                           keep_default_na=False, na_values=[''])
        tiene_equiv = 'Equivalencia' in df.columns
        info = {}
        for _, row in df.iterrows():
            cod = normalizar_codigo(row.get('Cuenta contable',''))
            if not cod or vacia(cod) or not cod.isdigit(): continue
            equiv_raw = str(row.get('Equivalencia','')) if tiene_equiv else ''
            equiv = normalizar_codigo(equiv_raw.split(' - ')[0]) if not vacia(equiv_raw) else ''
            info[cod] = {
                'tipo': 'A' if str(row.get('Tipo','')).strip().upper().startswith('A') else 'M',
                'req_ter': _si(row.get('Req. Tercero','')),
                'req_cc': _si(row.get('Req. C. Costos','')),
                'req_base': _si(row.get('Req. Base','')),
                'equiv': equiv,
            }
        return (info, etiqueta) if info else (None, '')
    except Exception:
        return None, ''


def parsear_cc_referencia(archivo):
    """Lee los Centros de Costos desde el informe del sistema o la plantilla de
    migración (hoja MIGRACION), con detección automática. Retorna set de códigos
    tipo auxiliar, o None si no se puede leer."""
    # ── Formato 1: plantilla de migración ──
    try:
        archivo.seek(0)
        df = pd.read_excel(archivo, sheet_name='MIGRACION', header=0, engine='openpyxl',
                           keep_default_na=False, na_values=[''])
        if 'Código' in df.columns and 'Tipo' in df.columns:
            aux = {normalizar_codigo(r.get('Código','')) for _, r in df.iterrows()
                   if not vacia(r.get('Código','')) and str(r.get('Tipo','')).strip().upper() in ('A','AUXILIAR')}
            if aux: return aux
    except Exception:
        pass

    # ── Formato 2: informe del sistema (Centro de costo) ──
    try:
        archivo.seek(0)
        crudo = pd.read_excel(archivo, header=None, engine='openpyxl', nrows=12)
        fila_hdr = next((i for i in range(len(crudo))
                         if str(crudo.iloc[i, 0]).strip().lower() == 'código'), None)
        if fila_hdr is None:
            return None
        archivo.seek(0)
        df = pd.read_excel(archivo, header=fila_hdr, engine='openpyxl',
                           keep_default_na=False, na_values=[''])
        aux = {normalizar_codigo(r.get('Código','')) for _, r in df.iterrows()
               if not vacia(r.get('Código','')) and str(r.get('Tipo','')).strip().upper().startswith('A')}
        return aux if aux else None
    except Exception:
        return None


@st.cache_data(show_spinner=False)
def _puc_ref_cacheado(contenido):
    """Versión cacheada: parsea el PUC solo si el contenido del archivo cambió."""
    return parsear_puc_referencia(BytesIO(contenido))


@st.cache_data(show_spinner=False)
def _cc_ref_cacheado(contenido):
    """Versión cacheada: parsea los Centros de Costos solo si el archivo cambió."""
    return parsear_cc_referencia(BytesIO(contenido))


@st.cache_data(show_spinner=False)
def _consecutivos_cacheado(contenido):
    """Versión cacheada del informe de consecutivos."""
