@st.cache_data(show_spinner=False)
def _tipos_doc_cacheado(contenido):
    """Versión cacheada del informe de tipos de documento."""
    return cargar_tipos_doc_personalizados(BytesIO(contenido))


def _sin_tildes(s):
    """Minúsculas y sin tildes, para comparar nombres de columnas."""
    s = str(s).lower().strip()
    for a, b in (('á','a'),('é','e'),('í','i'),('ó','o'),('ú','u'),('ñ','n')):
        s = s.replace(a, b)
    return s


@st.cache_data(show_spinner=False)
def _nits_terceros_cacheado(contenido):
    """Maestro de terceros → set de NITs. Soporta el informe del sistema
    (encabezado tras filas de título, columna 'No. de identificación') y
    cualquier archivo con columna NIT/identificación/RUC."""
    def _es_col_nit(c):
        c = _sin_tildes(c)
        return 'identificaci' in c or c == 'nit' or 'nit' in c.split() or 'ruc' in c

    try:
        # Detectar la fila del encabezado escaneando las primeras filas
        crudo = pd.read_excel(BytesIO(contenido), header=None, engine='openpyxl', nrows=12)
        fila_hdr = 0
        for i in range(len(crudo)):
            celdas = [_sin_tildes(c) for c in crudo.iloc[i].tolist() if c is not None and str(c).strip()]
            if any('identificaci' in c or c == 'nit' for c in celdas):
                fila_hdr = i
                break
        df_ter = pd.read_excel(BytesIO(contenido), header=fila_hdr, engine='openpyxl',
                               keep_default_na=False, na_values=[''])
        col_nit = next((c for c in df_ter.columns if _es_col_nit(c)), None)
        if col_nit:
            nits = {limpiar_nit(v) for v in df_ter[col_nit].tolist() if not vacia(v)}
            nits.discard('0')
            return nits if nits else None
    except Exception:
        pass
    return None


def leer_cuentas_cruce_pdf(archivo):
    """Lee el PDF de Cuentas Cruce exportado desde SINCO ERP.
    Soporta PDFs con texto digital y PDFs escaneados (usa OCR).
    Retorna lista de dicts: [{'cuenta': '130505', 'naturaleza': 'Cuentas por Cobrar', 'descripcion': 'NACIONALES'}, ...]
    """
    try:
        import pdfplumber
        cuentas = []

        def _parsear_lineas(texto):
            """Extrae cuentas desde texto plano usando patrones.
            Soporta formato en línea: 'Por Cobrar 130505 DESCRIPCION'
            Y formato columnar (OCR): Naturaleza, Código y Descripción en secciones separadas.
            """
            import re
            resultado = []
            lineas = [l.strip() for l in texto.split('\n') if l.strip()]

            # Intentar formato en línea primero
            for linea in lineas:
                m = re.match(r'^(Por\s+Cobrar|Por\s+Pagar)\s+(\d{4,12})\s+(.+)$', linea, re.IGNORECASE)
                if m:
                    naturaleza_raw, codigo, descripcion = m.group(1), m.group(2), m.group(3).strip()
                    naturaleza = 'Cuentas por Cobrar' if 'cobrar' in naturaleza_raw.lower() else 'Cuentas por Pagar'
                    resultado.append({'cuenta': limpiar_codigo(codigo), 'naturaleza': naturaleza, 'descripcion': descripcion})

            if resultado:
                return resultado

            # Formato columnar (OCR): extraer listas separadas y cruzarlas
            naturalezas, codigos, descripciones = [], [], []
            i = 0
            # Recopilar naturalezas
            while i < len(lineas):
                if lineas[i].strip().lower() in ('por cobrar', 'por pagar'):
                    naturalezas.append(lineas[i].strip())
                i += 1
            # Recopilar códigos (líneas numéricas de 4-12 dígitos)
            for l in lineas:
                if re.match(r'^\d{4,12}$', l):
                    codigos.append(l)
            # Recopilar descripciones (líneas en mayúsculas que no sean encabezados)
            skip = {'Naturaleza', 'Código', 'Descripción', 'Cuenta Contable', 'Requiere',
                    'Autorización', 'Ocultar', 'Anticipo', 'Eliminar', 'Guardar'}
            for l in lineas:
                if l.isupper() and len(l) > 3 and l not in skip and not re.match(r'^\d', l):
                    descripciones.append(l)
                elif re.match(r'^[A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑ\s\.\,\-\/\$]{3,}$', l) and l not in skip and not re.match(r'^\d', l) and len(l) > 5:
                    descripciones.append(l)

            # Cruzar las tres listas por índice
            for idx in range(min(len(naturalezas), len(codigos), len(descripciones))):
                nat = 'Cuentas por Cobrar' if 'cobrar' in naturalezas[idx].lower() else 'Cuentas por Pagar'
                resultado.append({'cuenta': limpiar_codigo(codigos[idx]), 'naturaleza': nat, 'descripcion': descripciones[idx]})
            return resultado

        def _parsear_tabla(tables):
            """Extrae cuentas desde tablas estructuradas del PDF.
            Tolera columnas adicionales: localiza la Naturaleza en cualquier posición
            de la fila y toma el código y la descripción de las celdas siguientes."""
            import re as _re
            resultado = []
            for table in tables:
                for row in table:
                    if not row: continue
                    celdas = [str(c).strip() if c is not None else '' for c in row]
                    # Caso 1: celda fusionada con la línea completa "Por pagar 249505 DESC"
                    fusionada = next((_re.match(r'^(por\s+cobrar|por\s+pagar)\s+(\d{4,12})\s+(.+)$', c, _re.IGNORECASE)
                                      for c in celdas
                                      if _re.match(r'^(por\s+cobrar|por\s+pagar)\s+\d{4,12}\s+', c, _re.IGNORECASE)), None)
                    if fusionada:
                        naturaleza = 'Cuentas por Cobrar' if 'cobrar' in fusionada.group(1).lower() else 'Cuentas por Pagar'
                        resultado.append({'cuenta': limpiar_codigo(fusionada.group(2)), 'naturaleza': naturaleza, 'descripcion': fusionada.group(3).strip()})
                        continue
                    # Caso 2: naturaleza, código y descripción en celdas separadas (posición variable)
                    idx_nat = next((i for i, c in enumerate(celdas)
                                    if _re.fullmatch(r'por\s+(cobrar|pagar)', c, _re.IGNORECASE)), None)
                    if idx_nat is None: continue
                    codigo = descripcion = ''
                    for c in celdas[idx_nat + 1:]:
                        if not c: continue
                        if not codigo and c.replace(' ', '').isdigit():
                            codigo = c
                        elif codigo:
                            descripcion = c
                            break
                    if not codigo: continue
                    naturaleza = 'Cuentas por Cobrar' if 'cobrar' in celdas[idx_nat].lower() else 'Cuentas por Pagar'
                    resultado.append({'cuenta': limpiar_codigo(codigo), 'naturaleza': naturaleza, 'descripcion': descripcion})
            return resultado

        with pdfplumber.open(archivo) as pdf:
            for page in pdf.pages:
                # Intentar primero con tablas (PDF con texto digital)
                tables = page.extract_tables()
                found = _parsear_tabla(tables)
                if found:
                    cuentas.extend(found)
                    continue
                # Si no hay tablas con datos, intentar con texto plano
                text = page.extract_text() or ''
                found = _parsear_lineas(text)
                if found:
                    cuentas.extend(found)
                    continue
                # Último recurso: OCR (PDF escaneado como imagen)
                try:
                    import pytesseract
                    img = page.to_image(resolution=200).original
                    ocr_text = pytesseract.image_to_string(img, lang='spa')
                    found = _parsear_lineas(ocr_text)
                    cuentas.extend(found)
                except ImportError:
                    pass  # pytesseract no disponible, continuar sin OCR

        # Eliminar duplicados por cuenta
        vistos = set()
        unicos = []
        for c in cuentas:
            if c['cuenta'] not in vistos:
                vistos.add(c['cuenta'])
                unicos.append(c)
        return unicos, None

    except ImportError:
        return [], 'pdfplumber no está instalado. Contacte al administrador.'
    except Exception as e:
        return [], f'Error leyendo el PDF: {e}'


