@st.cache_data(show_spinner=False)
def detectar_tipo_informe(contenido):
    """Identifica qué informe del sistema es un archivo, por su título y encabezados.
    Retorna una de: 'puc', 'centros_costos', 'terceros', 'consecutivos', 'tipos_doc',
    'plantilla_migracion' (las de SI/Mov/PUC-plantilla con hoja MIGRACION), o 'desconocido'."""
    try:
        # ¿Tiene hoja MIGRACION? → es una plantilla de migración (SI, Movimientos o PUC-plantilla)
        xls = pd.ExcelFile(BytesIO(contenido), engine='openpyxl')
        if 'MIGRACION' in xls.sheet_names:
            try:
                _cols = set(pd.read_excel(BytesIO(contenido), sheet_name='MIGRACION', nrows=0, engine='openpyxl').columns)
                # CxC y CxP se distinguen por su columna de saldo
                if 'Saldo CxC' in _cols:
                    return 'plantilla_cxc'
                if 'Saldo CxP' in _cols:
                    return 'plantilla_cxp'
                # Movimientos tiene Fecha/Tipo documento/Consecutivo; Saldos Iniciales no
                if {'Fecha del documento', 'Tipo documento', 'Consecutivo'} & _cols:
                    return 'plantilla_movimientos'
                if {'Débito', 'Crédito', 'Cuenta Contable'} <= _cols:
                    return 'plantilla_saldos_iniciales'
            except Exception:
                pass
            return 'plantilla_migracion'
        crudo = pd.read_excel(BytesIO(contenido), header=None, engine='openpyxl', nrows=8)
        textos = []
        for i in range(len(crudo)):
            for c in crudo.iloc[i].tolist():
                if c is not None and str(c).strip():
                    textos.append(_sin_tildes(c))
        blob = ' | '.join(textos)
        titulo = textos[0] if textos else ''

        # ¿Es un PUC? (por encabezados o título) → distinguir Principal/Fiscal por la etiqueta "PUC: X"
        es_puc = (('cuenta contable' in blob and ('req. c. costos' in blob or 'req. tercero' in blob or 'req c. costos' in blob))
                  or titulo.startswith('cuentas contables') or titulo == 'cuenta contable')
        if es_puc:
            if 'puc: principal' in blob or 'puc:principal' in blob:
                return 'puc_principal'
            if 'puc: fiscal' in blob or 'puc:fiscal' in blob:
                return 'puc_fiscal'
            if 'puc: nif' in blob or 'puc:nif' in blob:
                return 'puc_nif'
            return 'puc'  # PUC sin etiqueta clara: no distinguimos
        if 'tipo de documento' in blob and ('consecutivo' in blob or 'rango' in blob):
            return 'consecutivos'
        # Por título de la fila 1
        if titulo.startswith('centro de costo') or titulo.startswith('centros de costo'):
            return 'centros_costos'
        if 'tercero' in titulo:
            return 'terceros'
        if 'consecutivo' in titulo or 'verificacion de consecutivo' in blob:
            return 'consecutivos'
        if 'tipo' in titulo and 'documento' in titulo:
            return 'tipos_doc'
        # Terceros por encabezado
        if 'no. de identificacion' in blob or 'razon social' in blob:
            return 'terceros'
        # Centros de costo por encabezado simple (Código/Nombre/Tipo/Estado/Ciudad)
        if 'codigo' in blob and 'ciudad' in blob and 'estado' in blob:
            return 'centros_costos'
        return 'desconocido'
    except Exception:
        return 'desconocido'


def _validar_archivo_correcto(archivo, tipo_esperado, etiqueta_esperada):
    """Si el archivo cargado no corresponde al cajón, muestra aviso y retorna False."""
    if archivo is None:
        return True
    NOMBRES = {'puc':'un PUC (Cuentas Contables)', 'puc_principal':'el PUC Principal',
               'puc_fiscal':'el PUC Fiscal', 'puc_nif':'el PUC NIF', 'centros_costos':'Centros de Costo',
               'terceros':'el Maestro de Terceros', 'consecutivos':'Consecutivos',
               'tipos_doc':'Tipos de Documentos', 'plantilla_migracion':'una plantilla de migración',
               'plantilla_saldos_iniciales':'una plantilla de Saldos Iniciales',
               'plantilla_movimientos':'una plantilla de Movimientos',
               'plantilla_cxc':'una plantilla de Saldos CxC',
               'plantilla_cxp':'una plantilla de Saldos CxP'}
    detectado = detectar_tipo_informe(archivo.getvalue())
    if detectado == 'desconocido':
        return True  # no bloqueamos si no estamos seguros

    # Comparación tolerante entre familias PUC:
    # - tipo_esperado 'puc_principal'/'puc_fiscal'/'puc_nif': el detectado debe coincidir;
    #   pero un 'puc' genérico (sin etiqueta legible) se acepta sin alarma.
    es_familia_puc = lambda t: t in ('puc', 'puc_principal', 'puc_fiscal', 'puc_nif')
    es_familia_plantilla = lambda t: t in ('plantilla_migracion', 'plantilla_saldos_iniciales', 'plantilla_movimientos', 'plantilla_cxc', 'plantilla_cxp')
    if es_familia_puc(tipo_esperado):
        if not es_familia_puc(detectado):
            ok = False  # cargaron algo que ni siquiera es un PUC (ej. Centros de Costo)
        elif detectado == 'puc' or tipo_esperado == 'puc':
            ok = True   # alguno es genérico: no podemos afirmar que esté cruzado
        else:
            ok = (detectado == tipo_esperado)
    elif es_familia_plantilla(tipo_esperado):
        if not es_familia_plantilla(detectado):
            ok = False  # cargaron un informe del sistema donde va una plantilla
        elif detectado == 'plantilla_migracion':
            ok = True   # plantilla sin columnas que la distingan: no alarmamos
        else:
            ok = (detectado == tipo_esperado)
    else:
        ok = (detectado == tipo_esperado)

    if not ok:
        st.markdown(
            f'<div style="background:#7F1D1D;border:1px solid #DC2626;border-left:4px solid #FCA5A5;'
            f'border-radius:8px;padding:10px 14px;margin:-4px 0 10px;font-size:12px;color:#FEE2E2">'
            f'⚠️ Este archivo parece ser <b style="color:white">{NOMBRES.get(detectado, "otro informe")}</b>, '
            f'pero aquí va <b style="color:white">{etiqueta_esperada}</b>. Verifica que subiste el archivo correcto.</div>',
            unsafe_allow_html=True)
        return False
    return True


def parsear_empresa_de_informe(contenido):
    """Extrae (nombre_empresa, nit) del encabezado de un informe del sistema SINCO.
    Busca el patrón "EMPRESA - NIT 860,052,264 -0" en las primeras filas.
    Retorna ('', '') si no lo encuentra."""
    try:
        crudo = pd.read_excel(BytesIO(contenido), header=None, engine='openpyxl', nrows=6, usecols=[0])
        for i in range(len(crudo)):
            celda = str(crudo.iloc[i, 0]).strip()
            m = re.search(r'^(.*?)\s*-\s*NIT\s+([\d,\.]+)\s*-?\s*(\d?)\s*$', celda, re.IGNORECASE)
            if m:
                nombre = m.group(1).strip()
                nit = re.sub(r'[^0-9]', '', m.group(2))
                dv = m.group(3).strip()
                if dv: nit = f"{nit}-{dv}"
                return nombre, nit
    except Exception:
        pass
    return '', ''


