def exportar_excel_errores(plantillas_resultados):
    """Genera Excel con todos los errores para que el cliente corrija."""
    out = BytesIO()
    with pd.ExcelWriter(out, engine='openpyxl') as writer:
        for nombre, errores, df_orig in plantillas_resultados:
            rows = []
            for e in errores:
                rows.append({
                    'Fila en plantilla': e[0] if e[0] else 'General',
                    'Columna': e[1],
                    'Tipo': e[2].capitalize(),
                    'Qué debe corregir': e[3].replace('❌','').replace('⚠️','').strip(),
                })
            if rows:
                df_err = pd.DataFrame(rows)
                sheet = nombre[:31]
                df_err.to_excel(writer, sheet_name=sheet, index=False)
                ws = writer.sheets[sheet]
                ws.column_dimensions['A'].width = 18
                ws.column_dimensions['B'].width = 22
                ws.column_dimensions['C'].width = 12
                ws.column_dimensions['D'].width = 80
    return out.getvalue()



def parsear_informe_consecutivos(archivo):
    """Parsea el informe de Verificación de Consecutivos del sistema SINCO.
    Retorna dict: sigla_tipo_doc → lista de (consecutivo_inicial, consecutivo_final)
    Incluye rango principal, anulados y no contabilizados (todos ocupan el consecutivo).
    Tipos no homologables se guardan con su nombre completo normalizado como clave.
    """
    import unicodedata

    def _norm(s):
        s = str(s).strip().upper()
        s = unicodedata.normalize('NFD', s)
        return ''.join(c for c in s if unicodedata.category(c) != 'Mn')

    CATALOGO_DESC_SIGLA = {
        'COMPROBANTE DE EGRESO REVERSADO':'AE','AJUSTES POR INFLACION':'AI',
        'AJUSTES Y RECLASIFICACIONES':'AJ','AJUSTE DIFERENCIA EN CAMBIO':'AM',
        'ARRAS':'AR','DOCUMENTO SOPORTE REVERSADO':'AS','BAJA DE ACTIVOS':'BA',
        'NOTA CREDITO INMB. ADMINISTRADA':'C5','CIERRE ANUAL':'CA',
        'COMPROBANTE DE DIARIO':'CD','COMPROBANTE DE EGRESO':'CE',
        'CHEQUES POSFECHADOS':'CH','COMPROBANTE DE INGRESO':'CI',
        'CAUSACION MASIVA ENTRADAS SIN FACTURA':'CM','CUENTA POR PAGAR':'CP',
        'NOTA DEBITO INMB. ADMINISTRADA':'D5','DEPRECIACION':'DA',
        'DEVOLUCION CHEQUE':'DC','ABR DESEMBOLSO DE PRESTAMOS PROPIETARIOS':'DS',
        'DEVOLUCION O CANJE FACTURA':'DV','FACTURACION ANTICIPADA':'FA',
        'FACTURACION DIARIA':'FD','FACTURA DE VENTA':'FV',
        'GASTOS BANCARIOS AUTOMATICOS':'GA','GASTOS BANCARIOS':'GB',
        'GASTOS BANCARIOS MANUALES':'GM','AJUSTE POR INFLACION':'IC',
        'AJUSTE POR INFLACION DE LA DEPRECIACION':'ID',
        'INSTRUMENTOS FINANCIEROS':'IF',
        'COMPROBANTE DE LEGALIZACION INCAPACIDADES':'LI',
        'CAJA CHICA':'MC','MIGRACION FACTURAS':'MF',
        'ABR - MANTENIMIENTO DE INMUEBLES':'MI','AJUSTE MULTIMONEDA':'MM',
        'ABR - AJUSTES':'N1','ABR - AJUSTES ANTICIPADOS':'N2',
        'ABR - PAGOS ARRENDATARIOS POR CRUZAR':'N3','ABR - NOTAS CONTABLES':'N4',
        'NOTA CREDITO':'NC','NOTA DEBITO':'ND','NOMINA POR PAGAR':'NP',
        'DESEMBOLSO CAPITAL OB. FIN.':'OB','INTERESES OB. FIN.':'OI',
        'PRORRATAS OB. FIN.':'OP','RECLASIFICACION Y REVERSION OB. FIN.':'OR',
        'SUBROGACIONES OB. FIN.':'OS','UVR OB. FIN.':'OU',
        'ABONO CAPITAL PAT. AUT.':'PA','PARTIDAS CONCILIATORIAS INICIALES':'PD',
        'PAGO INTERESES PAT. AUT.':'PI','PROVISION NOMINA':'PM',
        'ABR - COBRO CUENTAS PROPIAS':'PP','ABR - PAGOS A TERCEROS':'PT',
        'RECIBO INMOBILIARIO ADMINISTRADO':'RA','RECIBO DE CAJA':'RC',
        'REEMBOLSABLES':'RE','REVERSION SALDOS MIGRADOS':'RM',
        'RESOLUCION DEL NEGOCIO':'RN','DOCUMENTO DE CARTERA REVERSADO':'RR',
        'REVALUACION ACTIVOS':'RV','SALIDAS ALMACEN':'SA',
        'SALDOS INICIALES':'SI','ABR DESCUENTO SERVICIOS PUBLICOS AL PROPIETARIO':'SP',
        'TRASLADO DE ANTICIPOS':'TA','TRASLADOS DE COSTOS':'TC',
        'CONSIGNACION':'TD','TRASLADO DE FONDOS':'TF','TRASLADO PRODUCTO':'TP',
        'NOTA EN VALOR':'VD','VALOR RESIDUAL':'VR'
    }
    DESC_A_SIGLA = {_norm(k): v for k, v in CATALOGO_DESC_SIGLA.items()}

    def _homologar(nombre):
        """Retorna sigla si es estándar, o nombre normalizado si es personalizado."""
        n = _norm(nombre)
        if n in DESC_A_SIGLA:
            return DESC_A_SIGLA[n]
        # Búsqueda parcial
        matches = [s for d, s in DESC_A_SIGLA.items() if n in d or d in n]
        return matches[0] if matches else n  # fallback: nombre normalizado

    def _es_numero(v):
        try: int(float(str(v).replace(',',''))); return True
        except: return False

    SKIP_META = {'CONSECUTIVO INICIAL', 'PRINCIPAL', 'FISCAL', 'NIF'}

    try:
        df = pd.read_excel(archivo, sheet_name=0, header=None, dtype=str)
    except Exception:
        return {}

    rangos = {}       # clave_tipo → [(ini, fin), ...]
    tipo_actual = None
    esperando_rango = False

    for _, row in df.iterrows():
        vals = [str(v).strip() for v in row.tolist()
                if str(v).strip() not in ('', 'nan', 'None', ' ')]
        if not vals:
            continue

        primera_norm = _norm(vals[0])

        # Saltar metadatos del encabezado
        if any(primera_norm.startswith(_norm(k)) for k in SKIP_META):
            continue

        # Detectar header de rango "Consecutivo inicial | Consecutivo final"
        if primera_norm == 'CONSECUTIVO INICIAL':
            esperando_rango = True
            continue

        # Detectar secciones secundarias — NO saltarlas, siguen acumulando rangos
        # "Documentos anulados" y "Documentos no contabilizados" generan rangos igualmente
        if primera_norm in ('DOCUMENTOS ANULADOS', 'DOCUMENTOS NO CONTABILIZADOS'):
            esperando_rango = False  # Los rangos vienen en filas siguientes sin header
            continue

        nums = [v for v in vals if _es_numero(v)]

        # Fila de rangos numéricos
        if len(nums) >= 2:
            i = 0
            while i + 1 < len(nums):
                try:
                    ini = int(float(nums[i].replace(',','')))
                    fin = int(float(nums[i+1].replace(',','')))
                    if tipo_actual and ini <= fin:
                        rangos.setdefault(tipo_actual, []).append((ini, fin))
                except Exception:
                    pass
                i += 2
            esperando_rango = False
            continue

        # Fila de un solo número (ej: "Documentos no contabilizados" con 1 elemento)
        if len(nums) == 1 and tipo_actual:
            try:
                v = int(float(nums[0].replace(',','')))
                rangos.setdefault(tipo_actual, []).append((v, v))
            except Exception:
                pass
            continue

        # Fila de texto sin números → nombre de tipo de documento
        if len(nums) == 0 and len(vals) == 1:
            tipo_actual = _homologar(vals[0])
            esperando_rango = False
            continue

    return rangos


def esta_en_rango_consecutivo(consecutivo, tipo_sigla, rangos_map):
    """Verifica si un consecutivo está ocupado en el sistema.
    Retorna (ini, fin) del rango donde cae, o None si está libre.
    """
    try:
        c = int(float(str(consecutivo).replace(',','')))
    except Exception:
        return None
    for ini, fin in rangos_map.get(tipo_sigla.strip().upper(), []):
        if ini <= c <= fin:
            return (ini, fin)
    return None

def exportar_plantilla_marcada(archivo_original, errores, nombre_libro):
    """Genera copia de la plantilla con celdas en error resaltadas en rojo."""
    from openpyxl import load_workbook
    from openpyxl.styles import PatternFill, Font, Alignment, Border, Side
    import copy

    ROJO_FILL   = PatternFill(start_color="FFCCCC", end_color="FFCCCC", fill_type="solid")
    ROJO_FONT   = Font(color="CC0000", bold=True)
    AMARILLO_FILL = PatternFill(start_color="FFF3CD", end_color="FFF3CD", fill_type="solid")
    AMARILLO_FONT = Font(color="856404")

    def _limpiar_msg(m):
        import re as _re
        m = str(m).replace('DOCUMENTO|', '').replace('PLANTILLA|', '')
        m = m.replace('<br>', ' ').replace('•', '-')
        m = _re.sub(r'<[^>]+>', '', m)  # quitar etiquetas HTML (<b>, etc.)
        return m.replace('❌', '').replace('⚠️', '').strip()

    try:
        try:
            archivo_original.seek(0)
        except Exception:
            pass
        wb = load_workbook(archivo_original)
        ws = wb['MIGRACION']

        # Obtener encabezados — fila 1
        headers = {}
        for cell in ws[1]:
            if cell.value:
                headers[str(cell.value).strip()] = cell.column

        # Errores con fila específica (para marcar celdas en rojo)
        errores_fila = [(e[0], e[1], e[2], e[3]) for e in errores if e[0] is not None]
        # Errores generales sin fila (Balance) — van solo a la hoja de inconsistencias
        errores_balance = [(e[0], e[1], e[2], e[3]) for e in errores if e[0] is None]

        # Marcar celdas en rojo (rápido). Los comentarios por celda se evitan porque
        # openpyxl los crea muy lento (miles de comentarios = más de un minuto);
        # en su lugar, un único comentario por encabezado de columna con el resumen,
        # y el detalle fila por fila va en la hoja 'Inconsistencias'.
        from openpyxl.comments import Comment
        resumen_por_columna = {}
        for fila_excel, columna, tipo, mensaje in errores_fila:
            col_idx = headers.get(columna)
            if not col_idx:
                continue
            try:
                cell = ws.cell(row=fila_excel, column=col_idx)
                cell.fill = ROJO_FILL
                cell.font = ROJO_FONT
            except Exception:
                continue
            if columna not in resumen_por_columna:
                resumen_por_columna[columna] = _limpiar_msg(mensaje)
        # Un comentario por columna, en su encabezado
        for columna, msg in resumen_por_columna.items():
            col_idx = headers.get(columna)
            if not col_idx:
                continue
            try:
                hcell = ws.cell(row=1, column=col_idx)
                c = Comment(f'Hay celdas con inconsistencias en esta columna. Revisa las celdas en rojo. Ejemplo: {msg}', 'Validador SINCO A&F')
                c.width, c.height = 320, 90
                hcell.comment = c
            except Exception:
                continue

        # Hoja de resumen de errores. El estilo se aplica SOLO al encabezado:
        # estilizar miles de filas una por una es lentísimo en openpyxl (puede tardar
        # más de un minuto). El detalle de cada fila se mantiene completo.
        if errores_fila or errores_balance:
            try: wb.remove(wb['Inconsistencias'])
            except: pass
            ws_err = wb.create_sheet('Inconsistencias')
            ws_err.append(['Fila', 'Columna', 'Categoría', 'Qué debe corregir'])
            from openpyxl.styles import PatternFill as PF
            hdr_fill = PF(start_color="1B3A6B", end_color="1B3A6B", fill_type="solid")
            hdr_font = Font(color="FFFFFF", bold=True)
            for cell in ws_err[1]:
                cell.fill = hdr_fill
                cell.font = hdr_font
            CAT = {'formato': 'Dato inválido', 'logica': 'Dato no encontrado', 'general': 'Balance'}
            # Primero los errores de balance (documentos descuadrados / plantilla)
            for fila_excel, columna, tipo, mensaje in errores_balance:
                ws_err.append([
                    'Documento' if 'descuadrado' in _limpiar_msg(mensaje).lower() or 'DOCUMENTO|' in str(mensaje) else 'General',
                    columna, CAT.get(tipo, tipo.capitalize()),
                    _limpiar_msg(mensaje)
                ])
            for fila_excel, columna, tipo, mensaje in errores_fila:
                ws_err.append([
                    fila_excel, columna, CAT.get(tipo, tipo.capitalize()),
                    _limpiar_msg(mensaje)
                ])
            ws_err.freeze_panes = 'A2'
            try: ws_err.auto_filter.ref = f"A1:D{ws_err.max_row}"
            except Exception: pass
            ws_err.column_dimensions['A'].width = 12
            ws_err.column_dimensions['B'].width = 22
            ws_err.column_dimensions['C'].width = 18
            ws_err.column_dimensions['D'].width = 90

        out = BytesIO()
        wb.save(out)
        return out.getvalue()
    except Exception as ex:
        return None


