# ETAPA 2 — FUNCIONES
# ─────────────────────────────────────────────────────────────────────────────

def _conv_fecha_excel(v):
    """Convierte serial Excel → dd/mm/aaaa, o devuelve el string tal cual."""
    if vacia(v):
        return ''
    s = str(v).strip()
    try:
        n = float(s)
        if 10000 < n < 100000:
            from datetime import date, timedelta
            origen = date(1899, 12, 30)
            return (origen + timedelta(days=int(n))).strftime('%d/%m/%Y')
    except Exception:
        pass
    return s


def _es_fecha_valida_e2(v):
    s = _conv_fecha_excel(v)
    if not s:
        return False
    for fmt in ('%d/%m/%Y', '%Y-%m-%d', '%d-%m-%Y', '%Y/%m/%d'):
        try:
            datetime.strptime(s.split(' ')[0], fmt)
            return True
        except Exception:
            pass
    return False


def _parse_fecha_e2(v):
    s = _conv_fecha_excel(v)
    if not s:
        return None
    for fmt in ('%d/%m/%Y', '%Y-%m-%d', '%d-%m-%Y', '%Y/%m/%d'):
        try:
            return datetime.strptime(s.split(' ')[0], fmt)
        except Exception:
            pass
    return None


def _es_decimal_valido(v, max_enteros=13, max_decimales=8):
    try:
        f = float(str(v).replace(',', '').strip())
        parte_entera = str(abs(int(f)))
        partes = str(v).replace(',', '').strip().split('.')
        parte_dec = partes[1] if len(partes) > 1 else ''
        return len(parte_entera) <= max_enteros and len(parte_dec) <= max_decimales
    except Exception:
        return False


def validar_cxc(df, nits_validos=None, puc_validos=None, ccs_validos=None):
    """
    Valida plantilla Saldos CxC (FxV).
    Columnas: Fecha del documento | Fecha de vencimiento | Número Factura |
              Consecutivo | Cuenta contable de cruce | Centro Costos |
              NIT | Saldo CxC | Sucursal | Tasa de cambio
    """
    errores = []
    consecutivos_vistos = {}

    for idx, row in df.iterrows():
        fila = idx + 2

        fecha_doc    = row.get('Fecha del documento', '')
        fecha_venc   = row.get('Fecha de vencimiento', '')
        num_factura  = str(row.get('Número Factura', '')).strip().lstrip("'")
        consecutivo  = str(row.get('Consecutivo', '')).strip().lstrip("'")
        cuenta_cruce = limpiar_codigo(row.get('Cuenta contable de cruce', ''))
        cc           = str(row.get('Centro Costos', '')).strip().lstrip("'")
        nit          = limpiar_nit(row.get('NIT', ''))
        saldo        = row.get('Saldo CxC', '')
        sucursal     = str(row.get('Sucursal', '')).strip().lstrip("'")
        tasa         = row.get('Tasa de cambio', '')

        vals_fila = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals_fila:
            continue

        # ── Fecha del documento ──
        if vacia(fecha_doc):
            errores.append((fila, 'Fecha del documento', 'formato',
                '❌ La Fecha del documento está vacía. Usa el formato dd/mm/aaaa.',
                'Campo vacío.'))
        elif not _es_fecha_valida_e2(fecha_doc):
            errores.append((fila, 'Fecha del documento', 'formato',
                f'❌ La fecha "{_conv_fecha_excel(fecha_doc)}" no tiene el formato correcto. Usa dd/mm/aaaa.',
                'Formato de fecha inválido.'))

        # ── Fecha de vencimiento ──
        if vacia(fecha_venc):
            errores.append((fila, 'Fecha de vencimiento', 'formato',
                '❌ La Fecha de vencimiento está vacía. Usa el formato dd/mm/aaaa.',
                'Campo vacío.'))
        elif not _es_fecha_valida_e2(fecha_venc):
            errores.append((fila, 'Fecha de vencimiento', 'formato',
                f'❌ La fecha de vencimiento "{_conv_fecha_excel(fecha_venc)}" no tiene el formato correcto. Usa dd/mm/aaaa.',
                'Formato de fecha inválido.'))
        else:
            dt_doc  = _parse_fecha_e2(fecha_doc)
            dt_venc = _parse_fecha_e2(fecha_venc)
            if dt_doc and dt_venc and dt_venc < dt_doc:
                errores.append((fila, 'Fecha de vencimiento', 'logica',
                    f'⚠️ La Fecha de vencimiento ({_conv_fecha_excel(fecha_venc)}) no puede ser anterior '                    f'a la Fecha del documento ({_conv_fecha_excel(fecha_doc)}). Corrígela.',
                    'Fecha vencimiento < fecha documento.'))

        # ── Número Factura ──
        if vacia(num_factura):
            errores.append((fila, 'Número Factura', 'formato',
                '❌ El Número de Factura está vacío. Es obligatorio.',
                'Campo vacío.'))

        # ── Consecutivo ──
        if vacia(consecutivo):
            errores.append((fila, 'Consecutivo', 'formato',
                '❌ El Consecutivo está vacío. Es obligatorio.',
                'Campo vacío.'))
        else:
            try:
                c_val = int(float(consecutivo.replace(',', '')))
                if not (-2147000000 <= c_val <= 2147000000):
                    errores.append((fila, 'Consecutivo', 'formato',
                        f'❌ El Consecutivo "{consecutivo}" está fuera del rango permitido '                        f'(-2.147.000.000 a 2.147.000.000).',
                        'Consecutivo fuera de rango.'))
                elif str(abs(c_val)).startswith('0') and str(abs(c_val)) != '0':
                    errores.append((fila, 'Consecutivo', 'formato',
                        f'❌ El Consecutivo "{consecutivo}" no puede iniciar por el dígito 0.',
                        'Consecutivo inicia en 0.'))
                else:
                    if c_val in consecutivos_vistos:
                        errores.append((fila, 'Consecutivo', 'formato',
                            f'❌ El Consecutivo "{c_val}" está duplicado. '                            f'Ya aparece en la fila {consecutivos_vistos[c_val]}. '                            f'Cada factura debe tener un consecutivo único.',
                            'Consecutivo duplicado en plantilla.'))
                    else:
                        consecutivos_vistos[c_val] = fila
            except (ValueError, TypeError):
                errores.append((fila, 'Consecutivo', 'formato',
                    f'❌ El Consecutivo "{consecutivo}" no es un número válido. Debe ser un número entero.',
                    'Consecutivo no numérico.'))

        # ── Cuenta contable de cruce ──
        if vacia(cuenta_cruce):
            errores.append((fila, 'Cuenta contable de cruce', 'formato',
                '❌ La Cuenta contable de cruce está vacía. Es obligatoria.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(cuenta_cruce):
            errores.append((fila, 'Cuenta contable de cruce', 'formato',
                f'❌ La Cuenta contable de cruce "{cuenta_cruce}" tiene letras o símbolos. Solo se permiten números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(cuenta_cruce):
            errores.append((fila, 'Cuenta contable de cruce', 'formato',
                f'❌ La Cuenta contable de cruce "{cuenta_cruce}" no es un número válido.',
                'No numérico.'))
        elif puc_validos is not None and cuenta_cruce not in puc_validos:
            errores.append((fila, 'Cuenta contable de cruce', 'logica',
                f'🔵 La Cuenta contable de cruce "{cuenta_cruce}" no existe en el PUC Principal. '
                f'Verifica que esté bien escrita o créala en el maestro de cuentas.',
                'Cuenta no encontrada en PUC.'))

        # ── Centro Costos ──
        if vacia(cc):
            errores.append((fila, 'Centro Costos', 'formato',
                '❌ El Centro de Costos está vacío. Es obligatorio en las plantillas CxC.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(cc):
            errores.append((fila, 'Centro Costos', 'formato',
                f'❌ El Centro de Costos "{cc}" tiene caracteres no permitidos. Solo se permiten números.',
                'Contiene caracteres especiales.'))
        elif ccs_validos is not None and cc not in ccs_validos:
            errores.append((fila, 'Centro Costos', 'logica',
                f'🔵 El Centro de Costos "{cc}" no existe en el informe de Centros de Costos. '
                f'Verifica que esté bien escrito o créalo en el maestro.',
                'Centro de Costos no encontrado.'))

        # ── NIT ──
        if vacia(nit):
            errores.append((fila, 'NIT', 'formato',
                '❌ El NIT está vacío. Es obligatorio en las plantillas CxC.',
                'Campo vacío.'))
        elif nits_validos is not None:
            nit_limpio = limpiar_nit(nit)
            if nit_limpio not in nits_validos:
                errores.append((fila, 'NIT', 'logica',
                    f'🔵 El NIT "{nit}" no está en el informe de Terceros. '
                    f'Verifica que esté bien escrito o agrégalo en la plantilla de Terceros.',
                    'Tercero no registrado.'))

        # ── Saldo CxC ──
        if vacia(saldo):
            errores.append((fila, 'Saldo CxC', 'formato',
                '❌ El Saldo CxC está vacío. Es obligatorio.',
                'Campo vacío.'))
        else:
            if pd.isna(pd.to_numeric(str(saldo).replace(',', ''), errors='coerce')):
                errores.append((fila, 'Saldo CxC', 'formato',
                    f'❌ El Saldo CxC "{saldo}" no es un número válido.',
                    'No decimal.'))

        # ── Sucursal ──
        if vacia(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                '❌ La Sucursal está vacía. Si no sabes cuál es, ingresa 0 para la sucursal principal.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                f'❌ La Sucursal "{sucursal}" tiene caracteres no permitidos. Solo puedes ingresar números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                f'❌ La Sucursal "{sucursal}" no es un número válido. Ingresa solo dígitos.',
                'No numérico.'))

        # ── Tasa de cambio ──
        if not vacia(tasa):
            tasa_val = pd.to_numeric(str(tasa).replace(',', ''), errors='coerce')
            if pd.isna(tasa_val):
                errores.append((fila, 'Tasa de cambio', 'formato',
                    f'❌ La Tasa de cambio "{tasa}" no es un número válido.',
                    'No decimal.'))
            elif not _es_decimal_valido(tasa):
                errores.append((fila, 'Tasa de cambio', 'formato',
                    f'❌ La Tasa de cambio "{tasa}" excede el rango permitido (máximo 13 enteros y 8 decimales).',
                    'Decimal fuera de rango.'))

    return errores


def validar_cxp(df, nits_validos=None, puc_validos=None, ccs_validos=None):
    """
    Valida plantilla Saldos CxP.
    Columnas: Fecha del documento | Fecha de vencimiento | Fecha transacción |
              Cuenta contable de cruce | Centro Costos | NIT |
              Factura del Proveedor | Saldo CxP | Sucursal | Tasa de cambio
    """
    errores = []

    for idx, row in df.iterrows():
        fila = idx + 2

        fecha_doc    = row.get('Fecha del documento', '')
        fecha_venc   = row.get('Fecha de vencimiento', '')
        fecha_trans  = row.get('Fecha transacción', '')
        cuenta_cruce = limpiar_codigo(row.get('Cuenta contable de cruce', ''))
        cc           = str(row.get('Centro Costos', '')).strip().lstrip("'")
        nit          = limpiar_nit(row.get('NIT', ''))
        factura_prov = str(row.get('Factura del Proveedor', '')).strip().lstrip("'")
        saldo        = row.get('Saldo CxP', '')
        sucursal     = str(row.get('Sucursal', '')).strip().lstrip("'")
        tasa         = row.get('Tasa de cambio', '')

        vals_fila = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals_fila:
            continue

        # ── Fecha del documento ──
        if vacia(fecha_doc):
            errores.append((fila, 'Fecha del documento', 'formato',
                '❌ La Fecha del documento está vacía. Usa el formato dd/mm/aaaa.',
                'Campo vacío.'))
        elif not _es_fecha_valida_e2(fecha_doc):
            errores.append((fila, 'Fecha del documento', 'formato',
                f'❌ La fecha "{_conv_fecha_excel(fecha_doc)}" no tiene el formato correcto. Usa dd/mm/aaaa.',
                'Formato de fecha inválido.'))

        # ── Fecha de vencimiento ──
        if vacia(fecha_venc):
            errores.append((fila, 'Fecha de vencimiento', 'formato',
                '❌ La Fecha de vencimiento está vacía. Usa el formato dd/mm/aaaa.',
                'Campo vacío.'))
        elif not _es_fecha_valida_e2(fecha_venc):
            errores.append((fila, 'Fecha de vencimiento', 'formato',
                f'❌ La fecha de vencimiento "{_conv_fecha_excel(fecha_venc)}" no tiene el formato correcto. Usa dd/mm/aaaa.',
                'Formato de fecha inválido.'))
        else:
            dt_doc  = _parse_fecha_e2(fecha_doc)
            dt_venc = _parse_fecha_e2(fecha_venc)
            if dt_doc and dt_venc and dt_venc < dt_doc:
                errores.append((fila, 'Fecha de vencimiento', 'logica',
                    f'⚠️ La Fecha de vencimiento ({_conv_fecha_excel(fecha_venc)}) no puede ser anterior '                    f'a la Fecha del documento ({_conv_fecha_excel(fecha_doc)}). Corrígela.',
                    'Fecha vencimiento < fecha documento.'))

        # ── Fecha transacción (opcional, pero si viene debe ser válida) ──
        if not vacia(fecha_trans) and not _es_fecha_valida_e2(fecha_trans):
            errores.append((fila, 'Fecha transacción', 'formato',
                f'❌ La Fecha de transacción "{_conv_fecha_excel(fecha_trans)}" no tiene el formato correcto. Usa dd/mm/aaaa.',
                'Formato de fecha inválido.'))

        # ── Cuenta contable de cruce ──
        if vacia(cuenta_cruce):
            errores.append((fila, 'Cuenta contable de cruce', 'formato',
                '❌ La Cuenta contable de cruce está vacía. Es obligatoria.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(cuenta_cruce):
            errores.append((fila, 'Cuenta contable de cruce', 'formato',
                f'❌ La Cuenta contable de cruce "{cuenta_cruce}" tiene letras o símbolos. Solo se permiten números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(cuenta_cruce):
            errores.append((fila, 'Cuenta contable de cruce', 'formato',
                f'❌ La Cuenta contable de cruce "{cuenta_cruce}" no es un número válido.',
                'No numérico.'))
        elif puc_validos is not None and cuenta_cruce not in puc_validos:
            errores.append((fila, 'Cuenta contable de cruce', 'logica',
                f'🔵 La Cuenta contable de cruce "{cuenta_cruce}" no existe en el PUC Principal. '
                f'Verifica que esté bien escrita o créala en el maestro de cuentas.',
                'Cuenta no encontrada en PUC.'))

        # ── Centro Costos ──
        if vacia(cc):
            errores.append((fila, 'Centro Costos', 'formato',
                '❌ El Centro de Costos está vacío. Es obligatorio en las plantillas CxP.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(cc):
            errores.append((fila, 'Centro Costos', 'formato',
                f'❌ El Centro de Costos "{cc}" tiene caracteres no permitidos. Solo puedes ingresar números.',
                'Contiene caracteres especiales.'))
        elif ccs_validos is not None and cc not in ccs_validos:
            errores.append((fila, 'Centro Costos', 'logica',
                f'🔵 El Centro de Costos "{cc}" no existe en el informe de Centros de Costos. '
                f'Verifica que esté bien escrito o créalo en el maestro.',
                'Centro de Costos no encontrado.'))

        # ── NIT ──
        if vacia(nit):
            errores.append((fila, 'NIT', 'formato',
                '❌ El NIT está vacío. Es obligatorio en las plantillas CxP.',
                'Campo vacío.'))
        elif nits_validos is not None:
            nit_limpio = limpiar_nit(nit)
            if nit_limpio not in nits_validos:
                errores.append((fila, 'NIT', 'logica',
                    f'⚠️ El NIT "{nit}" no está en el maestro de terceros. '                    f'Verifica que esté bien escrito o agrégalo en la plantilla de Terceros.',
                    'Tercero no registrado.'))

        # ── Factura del Proveedor ──
        if vacia(factura_prov):
            errores.append((fila, 'Factura del Proveedor', 'formato',
                '❌ El número de Factura del Proveedor está vacío. Es obligatorio.',
                'Campo vacío.'))

        # ── Saldo CxP ──
        if vacia(saldo):
            errores.append((fila, 'Saldo CxP', 'formato',
                '❌ El Saldo CxP está vacío. Es obligatorio.',
                'Campo vacío.'))
        else:
            if pd.isna(pd.to_numeric(str(saldo).replace(',', ''), errors='coerce')):
                errores.append((fila, 'Saldo CxP', 'formato',
                    f'❌ El Saldo CxP "{saldo}" no es un número válido.',
                    'No decimal.'))

        # ── Sucursal ──
        if vacia(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                '❌ La Sucursal está vacía. Si no sabes cuál es, ingresa 0 para la sucursal principal.',
                'Campo vacío.'))
        elif tiene_caracteres_especiales(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                f'❌ La Sucursal "{sucursal}" tiene caracteres no permitidos. Solo puedes ingresar números.',
                'Contiene caracteres especiales.'))
        elif not es_numerico(sucursal):
            errores.append((fila, 'Sucursal', 'formato',
                f'❌ La Sucursal "{sucursal}" no es un número válido. Ingresa solo dígitos.',
                'No numérico.'))

        # ── Tasa de cambio ──
        if not vacia(tasa):
            tasa_val = pd.to_numeric(str(tasa).replace(',', ''), errors='coerce')
            if pd.isna(tasa_val):
                errores.append((fila, 'Tasa de cambio', 'formato',
                    f'❌ La Tasa de cambio "{tasa}" no es un número válido.',
                    'No decimal.'))
            elif not _es_decimal_valido(tasa):
                errores.append((fila, 'Tasa de cambio', 'formato',
                    f'❌ La Tasa de cambio "{tasa}" excede el rango permitido (máximo 13 enteros y 8 decimales).',
                    'Decimal fuera de rango.'))

    return errores


def render_resultado_etapa2(errores, nombre, archivo_orig, df_orig):
    """Renderiza resultado de validación para CxC o CxP."""
    errs_fila      = [e for e in errores if e[0] is not None]
    advertencias   = [e for e in errs_fila if e[2] == 'advertencia']
    errores_reales = [e for e in errs_fila if e[2] != 'advertencia']
    total_errores  = len(errores_reales)

    if total_errores == 0:
        st.markdown(
            f'<div style="background:#F0FDF4;border-left:5px solid #16A34A;border-radius:10px;'            f'padding:14px 20px;margin-bottom:12px;font-size:14px;color:#14532D">'            f'✅ <b>¡Plantilla {nombre} lista!</b> No se encontraron errores. '            f'Puedes continuar con la importación.</div>',
            unsafe_allow_html=True
        )
        return

    st.markdown(
        f'<div style="background:#FEF2F2;border-left:5px solid #DC2626;border-radius:10px;'        f'padding:14px 20px;margin-bottom:12px;font-size:14px;color:#7F1D1D">'        f'⚠️ Hemos identificado algunas inconsistencias en tu plantilla <b>{nombre}</b>. '        f'A continuación encontrarás el detalle de cada una junto con la información necesaria para corregirlas.</div>',
        unsafe_allow_html=True
    )

    cols_con_errores = sorted(set(e[1] for e in errores_reales))
    for col in cols_con_errores:
        errs_col = [e for e in errores_reales if e[1] == col]
        tag_tipo = errs_col[0][2]
        tag_html = {'formato': '🔴 Dato inválido', 'logica': '🔵 Dato no encontrado', 'general': '🟡 Balance'}.get(tag_tipo, '📌')
        with st.expander(f"{col}", expanded=len(errs_col) <= 3):
            for e in errs_col:
                st.markdown(
                    f'<div style="background:white;border:1px solid #E2E8F0;border-radius:6px;'                    f'padding:8px 12px;margin:3px 0;font-size:13px">'                    f'<b style="color:#1B3A6B">Fila {e[0]}</b> &nbsp; {e[3]}</div>',
                    unsafe_allow_html=True
                )

    if advertencias:
        st.markdown("**⚠️ Advertencias:**")
        for e in advertencias:
            fila_txt = f"Fila {e[0]}" if e[0] else "General"
            st.markdown(
                f'<div style="background:#FFFBEB;border:1px solid #FDE68A;border-radius:6px;'
                f'padding:8px 12px;margin:3px 0;font-size:13px">'
                f'<b style="color:#D97706">{fila_txt}</b> &nbsp; {e[3]}</div>',
                unsafe_allow_html=True
            )


