def validar_puc(df, es_fiscal=False, df_principal=None):
    """
    Valida PUC Principal o Fiscal.
    Retorna lista de (fila, columna, tipo, mensaje_simple, mensaje_tecnico)
    """
    errores = []
    codigos_vistos     = {}
    descripciones_vistas = {}
    equivalencias_vistas = {}
    codigos_maestros   = set()

    # Helpers de detección por palabras clave
    def _es_retefuente(desc):
        d = desc.upper()
        return any(k in d for k in ['RETE FTE','RETEFTE','RETENCION EN LA FUENTE','RETENCIÓN EN LA FUENTE',
                                     'RETENCION FUENTE','RETENCIÓN FUENTE','RETEFUENTE','RETENCION EN LA F'])

    def _es_reteica(desc):
        d = desc.upper()
        return any(k in d for k in ['RETEICA','RETE ICA','RETENCION ICA','RETENCIÓN ICA',
                                     'RETENCION DE ICA','RETENCIÓN DE ICA','ICA RETENIDO','ICA RETENIDA',
                                     'INDUSTRIA Y COMERCIO RETEN','IND Y COMERCIO RETEN'])

    def _es_iva_mayor_costo(desc):
        d = desc.upper()
        return any(k in d for k in ['IVA MAYOR VALOR','IVA MAYOR COSTO','MAYOR VALOR COSTO',
                                     'IVA COSTO','IVA MAYOR DEL COSTO','IVA MAYOR VALOR DEL COSTO'])

    _MUNICIPIOS = [
        'BOGOTA','BOGOTÁ','MEDELLIN','MEDELLÍN','CALI','BARRANQUILLA','CARTAGENA','CUCUTA','CÚCUTA',
        'BUCARAMANGA','PEREIRA','MANIZALES','IBAGUE','IBAGUÉ','SANTA MARTA','VILLAVICENCIO','PASTO',
        'MONTERIA','MONTERÍA','SINCELEJO','VALLEDUPAR','NEIVA','ARMENIA','POPAYAN','POPAYÁN',
        'TUNJA','FLORENCIA','QUIBDO','QUIBDÓ','MOCOA','INIRIDA','INÍRIDA','MITÚ','LETICIA',
        'PUERTO CARREÑO','YOPAL','SAN ANDRES','SAN ANDRÉS','RIOHACHA','ARAUCA','BELLO','SOACHA',
        'SOLEDAD','ITAGUI','ITAGÜÍ','BUENAVENTURA','PALMIRA','DOSQUEBRADAS','MANIZALES',
        'BTA','BOG','MED','CAL','BAQ','CTG','CUC','BGA','PEI','MAN',
    ]

    def _tiene_municipio(desc):
        d = desc.upper()
        return any(m in d for m in _MUNICIPIOS)

    # Primer paso: recolectar maestros, auxiliares y grupos temáticos
    longitudes_aux   = {}
    padre_de         = {}   # cod_aux → cod_maestro_padre
    pct_por_padre    = {}   # cod_maestro → {pct: [cod_aux]}
    grupo_retefuente = {}   # cod_maestro_retefuente → [filas de auxiliares]
    grupo_reteica    = {}   # cod_maestro_reteica    → [descripciones]
    hay_iva_mayor    = False
    iva_mayor_filas  = []   # filas con IVA mayor valor del costo

    for idx, row in df.iterrows():
        cod  = normalizar_codigo(row.get('Código',''))
        tipo = str(row.get('Tipo','')).strip().upper()
        desc = str(row.get('Descripción','')).strip()
        if cod and tipo == 'M':
            codigos_maestros.add(cod)
        if cod and tipo == 'A' and cod.isdigit():
            longitudes_aux[cod] = len(cod)
            # Padre = el maestro más largo que sea prefijo de este auxiliar
            padre = max((m for m in codigos_maestros if cod.startswith(m) and cod != m),
                        key=len, default=None)
            if padre:
                padre_de[cod] = padre

    # Segundo paso: agrupar por tema usando descripción del maestro y del auxiliar
    for idx, row in df.iterrows():
        cod  = normalizar_codigo(row.get('Código',''))
        tipo = str(row.get('Tipo','')).strip().upper()
        desc = str(row.get('Descripción','')).strip()
        pct  = row.get('%','')
        req_base = str(row.get('Requiere Base','')).strip().upper()

        if _es_iva_mayor_costo(desc):
            hay_iva_mayor = True
            iva_mayor_filas.append((idx+2, cod, req_base, pct))

        if tipo == 'M':
            if _es_retefuente(desc):
                grupo_retefuente[cod] = []
            if _es_reteica(desc):
                grupo_reteica[cod] = []

        if tipo == 'A':
            padre = padre_de.get(cod)
            if _es_retefuente(desc) and padre:
                grupo_retefuente.setdefault(padre, [])
                if not any(cod in g for g in grupo_retefuente.values()):
                    grupo_retefuente[padre].append((idx+2, cod, pct))
            elif padre and padre in grupo_retefuente:
                grupo_retefuente[padre].append((idx+2, cod, pct))

            if _es_reteica(desc) and padre:
                grupo_reteica.setdefault(padre, [])
                grupo_reteica[padre].append(desc)
            elif padre and padre in grupo_reteica:
                grupo_reteica[padre].append(desc)

    # Códigos del PUC Principal para validar equivalencias
    codigos_principal = set()
    if es_fiscal and df_principal is not None:
        for _, row in df_principal.iterrows():
            cod = normalizar_codigo(row.get('Código',''))
            if cod: codigos_principal.add(cod)

    # ── Validaciones por fila ──
    for idx, row in df.iterrows():
        fila = idx + 2

        vals = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals: continue

        cod       = normalizar_codigo(row.get('Código',''))
        desc      = str(row.get('Descripción','')).strip()
        tipo      = str(row.get('Tipo','')).strip().upper()
        req_cc    = str(row.get('Requiere Centro Costo','')).strip().upper()
        req_ter   = str(row.get('Requiere Tercero','')).strip().upper()
        req_base  = str(row.get('Requiere Base','')).strip().upper()
        pct       = row.get('%','')
        base_min  = row.get('Base Mínima','')
        nat_con   = str(row.get('Naturaleza Contraria','')).strip().upper()
        plazo     = str(row.get('Plazo','')).strip()

        # ── Código ──
        if vacia(row.get('Código','')):
            errores.append((fila,'Código','formato',
                'La columna Código está vacía. Por favor ingresa el código de la cuenta contable.',
                'Campo vacío'))
        elif not es_entero(str(row.get('Código','')).replace(',','')):
            errores.append((fila,'Código','formato',
                f'El código "{row.get("Código","")}" no es válido. Los códigos de cuenta solo pueden contener números enteros, sin puntos ni comas.',
                'No numérico'))
        else:
            if len(cod) > 15:
                errores.append((fila,'Código','formato',
                    f'El código "{cod}" supera los 15 dígitos permitidos. Por favor usa un código más corto.',
                    'Longitud > 15'))
            if cod in codigos_vistos:
                errores.append((fila,'Código','formato',
                    f'El código "{cod}" ya fue registrado en la fila {codigos_vistos[cod]}. Cada código debe ser único.',
                    'Código duplicado'))
            else:
                codigos_vistos[cod] = fila
            if tipo == 'A':
                tiene_padre = any(cod.startswith(m) and cod != m for m in codigos_maestros)
                if not tiene_padre:
                    errores.append((fila,'Código','logica',
                        f'La cuenta auxiliar "{cod}" no tiene una cuenta maestra (padre) asociada. Verifica que el código maestro que la agrupa esté incluido.',
                        'Auxiliar sin maestro padre'))

        # ── Descripción ──
        if vacia(desc):
            errores.append((fila,'Descripción','formato',
                'La descripción de esta cuenta está vacía. Por favor escribe el nombre de la cuenta contable.',
                'Campo vacío'))
        elif tiene_caracteres_especiales_desc(desc):
            errores.append((fila,'Descripción','formato',
                f'La descripción "{desc[:30]}..." contiene caracteres especiales no permitidos (como < > [ ]). Por favor retíralos.',
                'Caracteres especiales'))
        else:
            desc_key = desc.upper().strip()
            if desc_key in descripciones_vistas:
                errores.append((fila,'Descripción','formato',
                    f'La descripción "{desc}" ya fue usada en la fila {descripciones_vistas[desc_key]}. Dos cuentas no pueden tener el mismo nombre.',
                    'Descripción duplicada'))
            else:
                descripciones_vistas[desc_key] = fila

        # ── Tipo ──
        if vacia(tipo):
            errores.append((fila,'Tipo','formato',
                'La columna Tipo está vacía. Debes indicar M (Maestro) o A (Auxiliar).',
                'Campo vacío'))
        elif tipo not in ('M','A'):
            errores.append((fila,'Tipo','formato',
                f'El valor "{tipo}" en Tipo no es válido. Usa M para cuentas maestras o A para cuentas auxiliares.',
                'Valor distinto de M/A'))

        # ── Flags N/S ──
        for campo, val, nombre_c in [
            ('Requiere Centro Costo', req_cc,  'Requiere Centro Costo'),
            ('Requiere Tercero',      req_ter, 'Requiere Tercero'),
            ('Requiere Base',         req_base,'Requiere Base'),
            ('Naturaleza Contraria',  nat_con, 'Naturaleza Contraria'),
        ]:
            if not vacia(val) and val not in ('N','S'):
                errores.append((fila, campo, 'formato',
                    f'La columna "{nombre_c}" tiene el valor "{val}", que no es válido. Solo puedes usar S (Sí) o N (No).',
                    'Valor distinto de N/S'))

        # ── Naturaleza Contraria — validación por palabras clave en descripción ──
        desc_up = desc.upper()

        _REQUIERE_NAT_CON = [
            ('DEPRECIAC',          'depreciación acumulada'),
            ('AMORTIZAC',          'amortización acumulada'),
            ('DETERIORO',          'deterioro de activos'),
            ('PROVISION CARTERA',  'provisión de cartera'),
            ('PROVISION DEUDORES', 'provisión de deudores'),
            ('AGOTAMIENTO',        'agotamiento acumulado'),
            ('PROVISION INVENT',   'provisión de inventarios'),
            ('PERDIDA POR DETER',  'pérdida por deterioro'),
        ]

        _NO_REQUIERE_NAT_CON = [
            ('INGRESO',     'ingresos'),
            ('VENTA ',      'ventas'),
            ('VENTAS ',     'ventas'),
            ('CAJA ',       'caja'),
            ('BANCO ',      'bancos'),
            ('INVENTARIO',  'inventarios'),
            ('ACTIVO FIJO', 'activos fijos'),
        ]

        for kw, nombre_kw in _REQUIERE_NAT_CON:
            if kw in desc_up:
                if nat_con != 'S':
                    errores.append((fila, 'Naturaleza Contraria', 'logica',
                        f'La cuenta "{desc}" corresponde a {nombre_kw} y debe tener Naturaleza Contraria = S, '
                        f'ya que su saldo es contrario a la naturaleza normal de su clase '
                        f'(débito en cuentas de naturaleza crédito o viceversa). '
                        f'Por favor cambia el valor a S.',
                        f'Naturaleza Contraria faltante — {nombre_kw}'))
                break

        for kw, nombre_kw in _NO_REQUIERE_NAT_CON:
            if kw in desc_up:
                if nat_con == 'S':
                    errores.append((fila, 'Naturaleza Contraria', 'advertencia',
                        f'💡 La cuenta "{desc}" corresponde a {nombre_kw} y normalmente no requiere Naturaleza Contraria = S. '
                        f'Verifica si esto es intencional.',
                        f'Naturaleza Contraria posiblemente incorrecta — {nombre_kw}'))
                break

        # ── % ──
        if not vacia(pct):
            try:
                p = float(str(pct).replace(',','.'))
                if not (0 <= p <= 100):
                    errores.append((fila,'%','formato',
                        f'El porcentaje "{pct}" está fuera del rango permitido. Ingresa un número entre 0 y 100.',
                        'Fuera de rango 0-100'))
            except:
                errores.append((fila,'%','formato',
                    f'El valor "{pct}" en la columna % no es un número válido.',
                    'No decimal'))

        # ── Requiere Base ↔ % ↔ Base Mínima ──
        if req_base == 'S':
            if vacia(pct):
                errores.append((fila,'%','formato',
                    f'La cuenta "{cod}" tiene Requiere Base = S pero no tiene % diligenciado. Ingresa la tarifa correspondiente.',
                    'Requiere Base S sin %'))
            if vacia(base_min):
                errores.append((fila,'Base Mínima','formato',
                    f'La cuenta "{cod}" tiene Requiere Base = S pero no tiene Base Mínima diligenciada. Ingresa el valor mínimo de la transacción.',
                    'Requiere Base S sin Base Mínima'))
        if not vacia(pct) and req_base != 'S':
            errores.append((fila,'Requiere Base','formato',
                f'La cuenta "{cod}" tiene % diligenciado pero Requiere Base no está en S. Si la cuenta aplica tarifa, debe marcarse con Requiere Base = S.',
                '% sin Requiere Base S'))

        # ── Base Mínima ──
        if not vacia(base_min) and not es_numerico(str(base_min)):
            errores.append((fila,'Base Mínima','formato',
                f'El valor "{base_min}" en Base Mínima no es un número válido.',
                'No decimal'))

        # ── Plazo ──
        if not vacia(plazo):
            p_norm = str(int(float(plazo))) if es_numerico(plazo) else plazo
            if p_norm not in ('0','1','2'):
                errores.append((fila,'Plazo','formato',
                    f'El valor "{plazo}" en Plazo no es válido. Usa: 0 para No aplica, 1 para Corto plazo o 2 para Largo plazo.',
                    'Valor distinto de 0/1/2'))

        # ── Equivalencia (solo PUC Fiscal) ──
        if es_fiscal:
            equiv     = normalizar_codigo(row.get('Equivalencia',''))
            equiv_raw = row.get('Equivalencia','')

            if tipo == 'M' and not vacia(equiv_raw):
                errores.append((fila,'Equivalencia','formato',
                    f'La cuenta maestra "{cod}" no puede tener equivalencia. Las equivalencias solo aplican para cuentas auxiliares.',
                    'Maestro con equivalencia'))

            if tipo == 'A' and not vacia(equiv_raw):
                if not es_entero(str(equiv_raw).replace(',','')):
                    errores.append((fila,'Equivalencia','formato',
                        f'El valor "{equiv_raw}" en Equivalencia no es válido. Solo puedes ingresar números enteros.',
                        'No numérico'))
                else:
                    if equiv in equivalencias_vistas:
                        errores.append((fila,'Equivalencia','formato',
                            f'La equivalencia "{equiv}" ya está asignada a otra cuenta (fila {equivalencias_vistas[equiv]}). Cada cuenta del PUC Principal solo puede tener una equivalencia.',
                            'Equivalencia duplicada'))
                    else:
                        equivalencias_vistas[equiv] = fila
                    if codigos_principal and equiv not in codigos_principal:
                        errores.append((fila,'Equivalencia','logica',
                            f'La equivalencia "{equiv}" no corresponde a ninguna cuenta del PUC Principal.',
                            'No existe en PUC Principal'))

            if tipo == 'A' and vacia(equiv_raw):
                errores.append((fila,'Equivalencia','advertencia',
                    f'La cuenta auxiliar "{cod}" no tiene equivalencia asignada, lo que indica que es exclusiva del libro NIF. Si esto es intencional, puedes ignorar este aviso.',
                    'Auxiliar sin equivalencia — exclusiva NIF'))

    # ── Validaciones de tarifas de retención en la fuente (por grupo maestro) ──
    for cod_padre, aux_list in grupo_retefuente.items():
        pcts_vistos = {}
        for fila_a, cod_a, pct_a in aux_list:
            if vacia(pct_a):
                continue
            try:
                pct_key = round(float(str(pct_a).replace(',','.')), 4)
            except:
                continue
            if pct_key in pcts_vistos:
                errores.append((fila_a, '%', 'logica',
                    f'La tarifa {pct_a}% ya existe en otra cuenta auxiliar bajo el mismo grupo de retención (fila {pcts_vistos[pct_key]}). '
                    f'Se recomienda tener una sola cuenta por tarifa de retención.',
                    'Tarifa de retención duplicada'))
            else:
                pcts_vistos[pct_key] = fila_a

    # ── Validación ReteICA: recomendar detallar por ciudad/municipio ──
    for cod_padre, descs in grupo_reteica.items():
        todas = [cod_padre] + descs
        if not any(_tiene_municipio(d) for d in todas):
            # Buscar la fila del maestro para referenciarla
            fila_padre = next(
                (idx+2 for idx, row in df.iterrows()
                 if normalizar_codigo(row.get('Código','')) == cod_padre),
                None
            )
            errores.append((fila_padre, 'Descripción', 'advertencia',
                f'💡 Las cuentas del grupo de ReteICA "{cod_padre}" no tienen ciudad o municipio especificado en su descripción. '
                f'Se recomienda crear una cuenta auxiliar por cada ciudad o municipio donde la empresa tenga operaciones '
                f'(ej: ICA RETENIDO BOGOTÁ, ICA RETENIDO MEDELLÍN). Esto facilita el control y la liquidación del impuesto por jurisdicción.',
                'ReteICA sin detalle de municipio'))

    # ── Validación IVA mayor valor del costo ──
    if not hay_iva_mayor:
        errores.append((None, 'Descripción', 'advertencia',
            '💡 No se encontró una cuenta contable para el IVA como mayor valor del costo. '
            'Se recomienda crear cuentas auxiliares para clasificar de forma independiente el IVA que se lleva al costo '
            '(servicios y/o compras), con Requiere Base = S y el % correspondiente diligenciado.',
            'Sin cuenta IVA mayor valor del costo'))
    else:
        for fila_i, cod_i, req_base_i, pct_i in iva_mayor_filas:
            if req_base_i != 'S':
                errores.append((fila_i, 'Requiere Base', 'formato',
                    f'La cuenta "{cod_i}" de IVA mayor valor del costo debe tener Requiere Base = S.',
                    'IVA mayor costo sin Requiere Base S'))
            if vacia(pct_i):
                errores.append((fila_i, '%', 'formato',
                    f'La cuenta "{cod_i}" de IVA mayor valor del costo debe tener el % diligenciado.',
                    'IVA mayor costo sin %'))

    # ── Uniformidad de dígitos en cuentas auxiliares ──
    if longitudes_aux:
        from collections import Counter as _Counter
        conteo = _Counter(longitudes_aux.values())
        long_estandar = conteo.most_common(1)[0][0]
        if len(conteo) > 1:
            fuera = {c: l for c, l in longitudes_aux.items() if l != long_estandar}
            for idx, row in df.iterrows():
                cod = normalizar_codigo(row.get('Código',''))
                if cod in fuera:
                    errores.append((idx+2, 'Código', 'advertencia',
                        f'La cuenta auxiliar "{cod}" tiene {fuera[cod]} dígitos, pero la mayoría tiene {long_estandar}. '
                        f'Se recomienda mantener la misma cantidad de dígitos en todas las auxiliares.',
                        'Longitud de auxiliar distinta al estándar.'))

    return errores

def validar_centros_costos(df, CIUDADES_DEPTO):
    """Valida plantilla de Centros de Costos."""
    errores = []
    codigos_vistos = {}
    codigos_maestros = set()

    # Primer paso: recolectar maestros para validar jerarquía
    for idx, row in df.iterrows():
        cod  = normalizar_codigo(row.get('Código',''))
        tipo = str(row.get('Tipo','')).strip().upper()
        if cod and tipo == 'M':
            codigos_maestros.add(cod)

    for idx, row in df.iterrows():
        fila = idx + 2
        vals = [str(v).strip() for v in row.tolist() if not vacia(v)]
        if not vals: continue

        cod      = normalizar_codigo(row.get('Código',''))
        desc     = str(row.get('Descripción','')).strip()
        tipo     = str(row.get('Tipo','')).strip().upper()
        depto    = str(row.get('Codigo Departamento','')).strip()
        ciudad   = str(row.get('Codigo Ciudad','')).strip()
        mandante = str(row.get('Mandante','')).strip()
        sucursal = str(row.get('Sucursal Administrativa','')).strip()

        # CC-01 Código vacío
        if vacia(row.get('Código','')):
            errores.append((fila,'Código','formato','La columna Código está vacía. Por favor ingresa el código del centro de costo.','Campo vacío'))
        elif not es_entero(str(row.get('Código','')).replace(',','')):
            errores.append((fila,'Código','formato',
                f'El código "{row.get("Código","")}" no es válido. Los códigos de centro de costo solo pueden contener números enteros.','No numérico'))
        elif len(cod) > 15:
            errores.append((fila,'Código','formato',
                f'El código "{cod}" supera el máximo de 15 caracteres permitido. Acorta el código del centro de costo.','Código supera 15 caracteres'))
        elif len(cod) % 2 != 0:
            errores.append((fila,'Código','logica',
                f'El código "{cod}" tiene {len(cod)} dígitos. Los centros de costo se estructuran por niveles de 2 en 2 dígitos (2, 4, 6, 8...). Verifica que el código respete esa estructura.','Código sin estructura de dígitos pares'))
        else:
            # CC-03 Duplicado
            if cod in codigos_vistos:
                errores.append((fila,'Código','formato',
                    f'El código "{cod}" ya fue registrado en la fila {codigos_vistos[cod]}. Cada centro de costo debe tener un código único.','Código duplicado'))
            else:
                codigos_vistos[cod] = fila
            # CC-04 Jerarquía: el auxiliar debe colgar de un maestro padre (prefijo)
            if tipo == 'A' and len(cod) % 2 == 0 and len(cod) > 2:
                padre_inmediato = cod[:-2]
                tiene_padre = any(cod.startswith(m) and cod != m for m in codigos_maestros)
                if not tiene_padre:
                    errores.append((fila,'Código','logica',
                        f'El centro de costos auxiliar "{cod}" no tiene un centro maestro (padre) asociado en la plantilla. Todo centro de costos auxiliar debe colgar de un maestro; verifica que el código del maestro "{padre_inmediato}" esté incluido en el archivo.',
                        'Auxiliar sin maestro padre'))

        # CC-05 Maestro con sucursal
        if tipo == 'M' and not vacia(sucursal):
            errores.append((fila,'Sucursal Administrativa','formato',
                'Los centros de costo de tipo Maestro no pueden tener Sucursal Administrativa asignada. Retira ese valor para las cuentas maestras.','Maestro con sucursal'))

        # CC-06 Ciudad sin departamento o viceversa
        tiene_depto  = not vacia(depto)
        tiene_ciudad = not vacia(ciudad)
        if tiene_depto != tiene_ciudad:
            errores.append((fila,'Codigo Departamento','formato',
                'Si registras una ciudad debes registrar también el departamento, y viceversa. Ambos campos deben estar completos o ambos vacíos.',
                'Ciudad sin departamento o viceversa'))
        elif tiene_depto and tiene_ciudad:
            if re.search(r'[^0-9]', depto):
                errores.append((fila,'Codigo Departamento','formato',
                    f'El código de departamento "{depto}" contiene caracteres no permitidos. El código debe ser numérico.',
                    'Caracteres especiales'))
            if re.search(r'[^0-9]', ciudad):
                errores.append((fila,'Codigo Ciudad','formato',
                    f'El código de ciudad "{ciudad}" contiene caracteres no permitidos. El código debe ser numérico.',
                    'Caracteres especiales'))
            if es_entero(depto) and es_entero(ciudad):
                clave = (normalizar_depto(depto), normalizar_ciudad(ciudad))
                if clave not in CIUDADES_DEPTO:
                    errores.append((fila,'Codigo Ciudad','logica',
                        f'La combinación de departamento "{depto}" y ciudad "{ciudad}" no corresponde a ningún municipio registrado. Verifica que ambos códigos sean correctos.',
                        'Combinación ciudad+departamento no registrada'))

        # CC-07/08 Descripción
        if vacia(desc):
            errores.append((fila,'Descripción','formato','La descripción del centro de costo está vacía. Por favor ingresa el nombre o descripción del centro de costo.','Campo vacío'))
        elif len(desc) > 50:
            errores.append((fila,'Descripción','formato',
                f'La descripción "{desc[:30]}..." es demasiado larga ({len(desc)} caracteres). El máximo permitido es 50 caracteres. Por favor acórtala.','Longitud > 50'))

        # CC-09/10 Tipo
        if vacia(tipo):
            errores.append((fila,'Tipo','formato',
                'La columna Tipo está vacía. Debes indicar M si el centro de costo es Maestro, o A si es Auxiliar.','Campo vacío'))
        elif tipo not in ('M','A'):
            errores.append((fila,'Tipo','formato',
                f'El valor "{tipo}" en la columna Tipo no es válido. Usa M para centros de costo maestros o A para auxiliares.','Valor distinto de M/A'))

        # CC-13 Mandante
        if not vacia(mandante) and not es_entero(mandante):
            errores.append((fila,'Mandante','formato',
                f'El valor "{mandante}" en la columna Mandante no es válido. Solo puedes ingresar números enteros.','No numérico'))

        # CC-14 Sucursal Administrativa
        if not vacia(sucursal) and not es_entero(sucursal):
            errores.append((fila,'Sucursal Administrativa','formato',
                f'El valor "{sucursal}" en la columna Sucursal Administrativa no es válido. Solo puedes ingresar números enteros.','No numérico'))

    return errores


